import{_ as e,o as a,c as s,a2 as r}from"./chunks/framework.DvFsUg-r.js";const o="/assets/aws_springboot-001.BGAFv8QA.png",i="/assets/2.YQVe8cyn.jpg",l="/assets/40.CzYGVRmm.jpg",p="/assets/41.BnV_3HOM.jpg",n="/assets/35.DHTRF1MC.jpg",m="/assets/36.B1PyNfLM.jpg",h="/assets/38.WH63qp96.jpg",g="/assets/39.DxwTY1v4.jpg",q=JSON.parse('{"title":"1/13 무료 aws + springboot 서버 구축","description":"","frontmatter":{"title":"1/13 무료 aws + springboot 서버 구축","date":"2023-03-25T11:01:00.000Z","tags":["SPRINGBOOT","AWS"],"category":"Setup","editLink":false,"lastUpdated":false},"headers":[],"relativePath":"blog-archive/setup/aws-springboot-01.md","filePath":"blog-archive/setup/aws-springboot-01.md"}'),c={name:"blog-archive/setup/aws-springboot-01.md"};function d(_,t,b,f,u,w){return a(),s("div",null,[...t[0]||(t[0]=[r('<p><img src="'+o+'" alt=""></p><h1 id="_1-사전준비" tabindex="-1"><i class="fas fa-server"></i> 1. 사전준비 <a class="header-anchor" href="#_1-사전준비" aria-label="Permalink to &quot;&lt;i class=&quot;fas fa-server&quot;&gt;&lt;/i&gt; 1. 사전준비&quot;">​</a></h1><p>aws + ubuntu 18 + mariadb + springboot 백엔드 서버 구축에 관련된 내용입니다.</p><h2 id="_1-구축-조건" tabindex="-1">1. 구축 조건 <a class="header-anchor" href="#_1-구축-조건" aria-label="Permalink to &quot;1. 구축 조건&quot;">​</a></h2><p>서버를 구축할때 아래의 조건에 맞게 구축되어야 된다는 원칙을 정하고 방법을 찾았습니다.</p><ul><li>비용이 발생하면 안됩니다.</li><li>완벽하게 https 를 지원해 주어야 됩니다.</li><li>springboot 지원가능해야 됩니다.</li><li>구축해야 되는 서버는 오로지 <a href="https://goodsaem.github.io" target="_blank" rel="noreferrer">https://goodsaem.github.io</a> 사이트에서 요청한 데이터만 응답해야 됩니다.</li><li>mariadb 도 사용할수 있어야 됩니다.</li></ul><p>이런 조건을 맞추기 위해서는 <strong>aws 서버 구축</strong>이 정답이였습니다. 1년간 프리티어로 무료로 사용할수 있기에 회원가입을 하고 신용카드를 등록하여 프리티어 서버를 구축했습니다.</p><h2 id="_2-아키텍처" tabindex="-1">2. 아키텍처 <a class="header-anchor" href="#_2-아키텍처" aria-label="Permalink to &quot;2. 아키텍처&quot;">​</a></h2><ol><li>사용자가 브라우저를 통해서 <a href="https://goodsaem.github.io" target="_blank" rel="noreferrer">https://goodsaem.github.io</a> 를 접속합니다.</li><li>데이터를 저장하거나 데이터를 db 조회가 필요한경우 <a href="https://goodsaem.ml" target="_blank" rel="noreferrer">https://goodsaem.ml</a> 로 rest api를 호출합니다. <ul><li><a href="https://goodsaem.ml" target="_blank" rel="noreferrer">https://goodsaem.ml</a> aws 프리티어 서버에 구축되어 있습니다.</li><li><a href="https://goodsaem.github.io" target="_blank" rel="noreferrer">https://goodsaem.github.io</a> 에서 오는 요청 및 localhost에서 실행한 요청에 대해서만 허용하고 나머지는 거부합니다.</li></ul></li><li>nginx 웹서버는 <a href="https://goodsaem.github.io" target="_blank" rel="noreferrer">https://goodsaem.github.io</a> 에서 호출한 요청에 대해서만 응답하고 나머지 요청은 전부 거부하도록 설정합니다.</li><li><a href="https://goodsaem.ml/spring/" target="_blank" rel="noreferrer">https://goodsaem.ml/spring/</a> 으로 오는 요청은 spring boot가 응답하도록 설정합니다.</li><li>db는 mariadb를 사용하며 spring에서 데이터 crud가 필요한 경우 동작하도록 설계합니다.</li></ol><p><img src="'+i+'" alt=""></p><h2 id="_3-목표" tabindex="-1">3. 목표 <a class="header-anchor" href="#_3-목표" aria-label="Permalink to &quot;3. 목표&quot;">​</a></h2><p>서버 셋업이 완료되고 나서 ssl 수준이 얼마나 되는지 체크하는 사이트<a href="https://www.ssllabs.com/ssltest/analyze.html" target="_blank" rel="noreferrer">https://www.ssllabs.com/ssltest/analyze.html</a>에 점검한 결과 입니다. A를 받았으니 잘 설정한것 같네요 ^^</p><p><img src="'+l+'" alt=""></p><p><img src="'+p+'" alt=""></p><h2 id="_4-무료-도메인-발급" tabindex="-1">4. 무료 도메인 발급 <a class="header-anchor" href="#_4-무료-도메인-발급" aria-label="Permalink to &quot;4. 무료 도메인 발급&quot;">​</a></h2><p>무료 도메인 발급 받는 방법에 대해서 알아 보겠습니다.</p><p>요즘 대부분의 웹서버는 https 통신을 합니다. 이제는 선택이 아닌 필수 인것 같네요 제가 서버를 구축하게 된 직접적인 원인도 https 설정을 하기 위함입니다. nginx 에 https 서비스를 구성하기 위해서는 도메인이 필요합니다. 도메인이 준비되면 certbot을 통해서 무료 ssl 인증서 적용 및 http/2 적용이 가능한데요 무료 도메인 가입하는 부분에 대해서 아래오 같이 정리했습니다. 서버셋업전 도메인 발급 받으시기 바랍니다.</p><h2 id="_5-freenom" tabindex="-1">5. Freenom <a class="header-anchor" href="#_5-freenom" aria-label="Permalink to &quot;5. Freenom&quot;">​</a></h2><p>Freenom 에서 무료 도메인 발급 받는 방법입니다.</p><p><a href="https://www.freenom.com/en/index.html?lang=en" target="_blank" rel="noreferrer">https://www.freenom.com/en/index.html?lang=en</a> freenom 이란 사이트에서 무료 도메인을 발급 받을수 있습니다. 회원가입을 후 도메인 등록을 진행합니다.</p><ul><li><p>로그인 후 원하는 도메인을 입력하고 엔터키를 클릭한후 사용하고자 하는 도메인에서 Get it now! 버튼을 클릭하여 선택합니다. 그리고 나서 <strong>Checkout</strong> 버튼을 클릭합니다.</p><p><img src="'+n+'" alt=""></p></li><li><p>Use DNS 버튼을 클릭하고 Use Freenom DNS Service를 선택한후 aws free tier의 퍼블릭 ipv4 주소를 입력하고 Continue 버튼을 클릭합니다.</p><p><img src="'+m+'" alt=""></p></li><li><p>도메인 주문이 완료되었습니다.</p><p><img src="'+h+'" alt=""></p></li><li><p>My Domain 에서 주문한 도메인 확인이 가능합니다.</p><div class="tip custom-block"><p class="custom-block-title">goodsaem.ml</p><p>무료 도메인을 2개 신청했는데 2번째꺼는 어떤이유인지 mydomain에 추가 되지 않아 goodsaem.ml로 셋팅 진행하겠습니다.</p></div><p><img src="'+g+'" alt=""></p></li></ul>',21)])])}const x=e(c,[["render",d]]);export{q as __pageData,x as default};
